def strip_yaml_quotes(value: str) -> str:
    if len(value) >= 2 and value[0] == value[-1] and value[0] in {"'", '"'}:
        return value[1:-1]
    return value


def parse_yaml_scalar(path: Path, line_number: int, value: str) -> object:
    if value in {"[]", "{}"}:
        return [] if value == "[]" else {}
    if value.lower() in {"true", "false"}:
        return value.lower() == "true"
    if value.lower() in {"null", "~"}:
        return None
    if value.isdigit():
        return int(value)
    for opening, closing in (("[", "]"), ("{", "}")):
        if value.count(opening) != value.count(closing):
            raise YamlSyntaxError(
                f"{path.relative_to(ROOT)}:{line_number}: unbalanced {opening}{closing}"
            )
    return strip_yaml_quotes(value)


def read_yaml_lines(path: Path) -> list[tuple[int, str, int]]:
    lines: list[tuple[int, str, int]] = []
    for line_number, raw_line in enumerate(path.read_text(encoding="utf-8").splitlines(), 1):
        if "\t" in raw_line[: len(raw_line) - len(raw_line.lstrip())]:
            raise YamlSyntaxError(
                f"{path.relative_to(ROOT)}:{line_number}: tabs are not allowed in indentation"
            )
        content = raw_line.split(" #", 1)[0].rstrip()
        stripped = content.strip()
        if not stripped or stripped in {"---", "..."}:
