def validate_json() -> None:
    count = 0
    for path in ROOT.rglob("*.json"):
        if should_ignore(path):
            continue
        with path.open(encoding="utf-8") as handle:
            json.load(handle)
        count += 1
    print(f"validated {count} json files")


def validate_yaml() -> None:
    count = 0
    for pattern in ("*.yaml", "*.yml"):
        for path in ROOT.rglob(pattern):
            if should_ignore(path):
                continue
            if is_helm_template(path):
                continue
            load_yaml(path)
            count += 1
    print(f"validated {count} non-template yaml files")


def validate_helm_metadata() -> None:
    chart_path = ROOT / "infrastructure/helm/healthbridge/Chart.yaml"
    values_path = ROOT / "infrastructure/helm/healthbridge/values.yaml"
    chart = load_yaml(chart_path)
    if not isinstance(chart, dict):
        raise ValueError(f"{chart_path.relative_to(ROOT)} must be a YAML mapping")
    for field in ("apiVersion", "name", "version", "type"):
        if not chart.get(field):
            raise ValueError(f"{chart_path.relative_to(ROOT)} missing required field: {field}")
    values = load_yaml(values_path)
    if not isinstance(values, dict):
        raise ValueError(f"{values_path.relative_to(ROOT)} must be a YAML mapping")
    image = values.get("image", {})
    if not isinstance(image, dict):
        raise ValueError(f"{values_path.relative_to(ROOT)} image must be a mapping")
    if not image.get("repository") or not image.get("tag"):
        raise ValueError(f"{values_path.relative_to(ROOT)} must define image.repository and image.tag")
    print("validated Helm chart metadata")


def validate_database_files() -> None:
    schema = ROOT / "database/schema.sql"
    migrations = sorted((ROOT / "database/migrations").glob("*.sql"))
    if not schema.read_text(encoding="utf-8").strip():
        raise ValueError("database/schema.sql is empty")
    if not migrations:
        raise FileNotFoundError("database/migrations does not contain SQL migrations")
    print(f"validated database schema and {len(migrations)} migrations are available")


def validate_docker_inputs() -> None:
    dockerfiles = sorted(ROOT.glob("services/*/Dockerfile"))
    dockerfiles += sorted((ROOT / "infrastructure/docker").glob("*.Dockerfile"))
    if not dockerfiles:
        raise FileNotFoundError("no Dockerfiles found")
    for dockerfile in dockerfiles:
        text = dockerfile.read_text(encoding="utf-8")
        if "FROM " not in text:
            raise ValueError(f"{dockerfile.relative_to(ROOT)} is missing a FROM instruction")
    print(f"validated {len(dockerfiles)} Docker build input files")


